           return replaceInstUsesWith(SI, V);

+    // Handle pattern: select (select X, (icmp sgt A, -1), false), (icmp slt A, C), false
+    // --> select X, (icmp ult A, C), false
+    // This is valid because if C is non-negative, (A >= 0) && (A < C) == (A u< C)
+    if (auto *InnerSel = dyn_cast<SelectInst>(CondVal)) {
+      // InnerSel must be a logical and: select X, Y, false
+      if (match(InnerSel->getFalseValue(), m_Zero())) {
+        if (auto *InnerICmp = dyn_cast<ICmpInst>(InnerSel->getTrueValue())) {
+          if (auto *OuterICmp = dyn_cast<ICmpInst>(TrueVal)) {
+            // Check if InnerICmp is (A sgt -1) and OuterICmp is (A slt C) where C >= 0
+            Value *A = InnerICmp->getOperand(0);
+            Value *InnerOp1 = InnerICmp->getOperand(1);
+            // InnerICmp must be: icmp sgt A, -1
+            if (InnerICmp->getPredicate() == ICmpInst::ICMP_SGT) {
+              if (auto *InnerConst = dyn_cast<ConstantInt>(InnerOp1)) {
+                if (InnerConst->isAllOnesValue()) {
+                  // Now check OuterICmp: icmp slt A, C where C >= 0
+                  ICmpInst::Predicate OuterPred = OuterICmp->getPredicate();
+                  Value *OuterOp0 = OuterICmp->getOperand(0);
+                  Value *OuterOp1 = OuterICmp->getOperand(1);
+                  const APInt *C;
+                  // Handle (icmp slt A, C)
+                  if (OuterOp0 == A && OuterPred == ICmpInst::ICMP_SLT &&
+                      match(OuterOp1, m_APInt(C)) && C->isNonNegative()) {
+                    Value *NewICmp = Builder.CreateICmp(ICmpInst::ICMP_ULT, A, OuterOp1);
+                    return SelectInst::Create(InnerSel->getOperand(0), NewICmp, Zero);
+                  }
+                  // Handle swapped (icmp sgt C, A) which is equivalent to (icmp slt A, C)
+                  if (OuterOp1 == A && OuterPred == ICmpInst::ICMP_SGT &&
+                      match(OuterOp0, m_APInt(C)) && C->isNonNegative()) {
+                    Value *NewICmp = Builder.CreateICmp(ICmpInst::ICMP_ULT, A, OuterOp0);
+                    return SelectInst::Create(InnerSel->getOperand(0), NewICmp, Zero);
+                  }
+                }
+              }
+            }
+          }
+        }
+      }
+    }
